import{_ as t,o as i,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"导航、表单、列表与详情","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/00-foundations/03-navigation-form-list-detail.md","filePath":"03-interaction-design/notes/00-foundations/03-navigation-form-list-detail.md","lastUpdated":null}'),r={name:"03-interaction-design/notes/00-foundations/03-navigation-form-list-detail.md"};function n(s,a,d,o,h,p){return i(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="导航、表单、列表与详情" tabindex="-1">导航、表单、列表与详情 <a class="header-anchor" href="#导航、表单、列表与详情" aria-label="Permalink to &quot;导航、表单、列表与详情&quot;">​</a></h1><p>导航、表单、列表和详情是任务型产品最常见的四类结构。它们分别解决“去哪里”“输入或修改什么”“有哪些对象”“这个对象是什么及能做什么”。一个界面可以同时包含四者，但每个区域应有明确职责。</p><h2 id="概念与边界" tabindex="-1">概念与边界 <a class="header-anchor" href="#概念与边界" aria-label="Permalink to &quot;概念与边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>结构</th><th>主要对象</th><th>用户问题</th><th>典型结果</th></tr></thead><tbody><tr><td>导航</td><td>目的地与位置关系</td><td>我在哪里，还能去哪里？</td><td>进入另一个内容上下文</td></tr><tr><td>表单</td><td>字段、约束与提交</td><td>需要提供什么，输入是否有效？</td><td>创建或修改数据</td></tr><tr><td>列表</td><td>同类对象集合</td><td>有哪些，怎样找到和比较？</td><td>定位、选择或批量处理对象</td></tr><tr><td>详情</td><td>单个对象及其关系</td><td>它当前是什么状态，能做什么？</td><td>理解或操作一个对象</td></tr></tbody></table><p>筛选控件改变当前集合，不等于导航；Tab 在同一上下文中切换互斥面板，不应用来表示任意站点层级；表格强调行列关系，卡片和普通列表强调逐项浏览，三者不能只按视觉偏好互换。</p><h2 id="组合机制" tabindex="-1">组合机制 <a class="header-anchor" href="#组合机制" aria-label="Permalink to &quot;组合机制&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N[&quot;导航：选择内容范围&quot;] --&gt; L[&quot;列表：定位对象&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; D[&quot;详情：理解对象状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[&quot;表单：创建或修改&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; V[&quot;校验与提交&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt;|成功| D</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt;|失败| F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; L</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这不是固定页面顺序。移动端可能以多个页面呈现，宽屏管理工具可能同时显示列表与详情。无论布局如何变化，对象标识、筛选条件、选中项和编辑状态都应保持一致。</p><h2 id="导航设计" tabindex="-1">导航设计 <a class="header-anchor" href="#导航设计" aria-label="Permalink to &quot;导航设计&quot;">​</a></h2><h3 id="导航层级" tabindex="-1">导航层级 <a class="header-anchor" href="#导航层级" aria-label="Permalink to &quot;导航层级&quot;">​</a></h3><ul><li><strong>全局导航</strong>：产品主要区域，如项目、报表、设置。</li><li><strong>局部导航</strong>：当前区域内的同级目的地。</li><li><strong>上下文导航</strong>：与当前对象直接相关的目的地，如父项目、关联工单。</li><li><strong>面包屑</strong>：表达当前页面在层级结构中的祖先路径，不代替全局导航。</li><li><strong>页内导航</strong>：跳转当前长页面的标题或区域，不改变内容对象。</li></ul><p>导航项应使用目的地名称；按钮应使用动作名称。点击“项目”进入项目集合属于导航，点击“新建项目”触发创建动作属于按钮。</p><h3 id="必须定义的状态" tabindex="-1">必须定义的状态 <a class="header-anchor" href="#必须定义的状态" aria-label="Permalink to &quot;必须定义的状态&quot;">​</a></h3><ul><li>当前项与非当前项在视觉和程序语义上可区分；仅靠颜色不够。</li><li>目的地不可用时，说明是隐藏、禁用还是允许进入后解释权限。</li><li>窄屏折叠后，菜单的打开状态、焦点与关闭方式明确。</li><li>深链打开时，页面标题、导航当前项和面包屑保持一致。</li><li>键盘焦点按文档顺序移动，提供跳过重复导航进入主内容的机制。</li></ul><h2 id="表单设计" tabindex="-1">表单设计 <a class="header-anchor" href="#表单设计" aria-label="Permalink to &quot;表单设计&quot;">​</a></h2><h3 id="字段结构" tabindex="-1">字段结构 <a class="header-anchor" href="#字段结构" aria-label="Permalink to &quot;字段结构&quot;">​</a></h3><p>每个字段至少包含可见标签、输入控件、必要说明、必填状态和错误位置。相关选择可用 <code>fieldset</code> 与 <code>legend</code> 分组。占位符在输入后会消失，不能代替标签。</p><p>字段顺序应符合用户准备信息和完成任务的顺序。只收集完成当前事务必要的数据；额外字段会增加理解、输入、校验和隐私成本。</p><h3 id="校验时机" tabindex="-1">校验时机 <a class="header-anchor" href="#校验时机" aria-label="Permalink to &quot;校验时机&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时机</th><th>适合</th><th>风险</th></tr></thead><tbody><tr><td>输入过程中</td><td>字符计数、明确格式约束</td><td>过早报错会打断尚未完成的输入</td></tr><tr><td>离开字段后</td><td>可独立判断的字段</td><td>用户可能还会返回修改关联字段</td></tr><tr><td>提交后</td><td>跨字段规则、服务端权威校验</td><td>若只在顶部报错，用户难以定位</td></tr></tbody></table><p>提交失败时保留合法输入，并同时提供错误摘要和字段附近的具体错误。错误消息要说明问题及修正方法，如“截止日期必须晚于开始日期”，而不是“输入无效”。客户端校验改善反馈速度，服务端仍需执行权威校验。</p><h3 id="键盘与状态" tabindex="-1">键盘与状态 <a class="header-anchor" href="#键盘与状态" aria-label="Permalink to &quot;键盘与状态&quot;">​</a></h3><ul><li>使用原生控件和语义标签，保持自然 Tab 顺序，避免正 <code>tabindex</code>。</li><li>Enter 是否提交取决于控件和表单语义；多行文本中的 Enter 应换行。</li><li>提交中阻止重复写入，并显示可感知的等待状态。</li><li>超时、断网或服务端失败后保留输入，说明是否已保存。</li><li>成功结果必须明确，必要时通过状态消息让辅助技术获知动态变化。</li></ul><h2 id="列表设计" tabindex="-1">列表设计 <a class="header-anchor" href="#列表设计" aria-label="Permalink to &quot;列表设计&quot;">​</a></h2><h3 id="先定义比较任务" tabindex="-1">先定义比较任务 <a class="header-anchor" href="#先定义比较任务" aria-label="Permalink to &quot;先定义比较任务&quot;">​</a></h3><p>列表项展示什么，取决于用户据以识别、比较和决策的属性。先写出：</p><ul><li>主标识，如项目名或订单号；</li><li>关键状态，如逾期、草稿、已退款；</li><li>用于比较的数值或日期；</li><li>常用行级操作与批量操作；</li><li>默认排序及其业务含义。</li></ul><p>关系明确、需要跨行比较时使用语义表格；每项内容结构较松、需要逐项浏览时使用列表；卡片适合多种内容类型与较强视觉预览，但会降低密集比较效率。</p><h3 id="集合状态" tabindex="-1">集合状态 <a class="header-anchor" href="#集合状态" aria-label="Permalink to &quot;集合状态&quot;">​</a></h3><ul><li>初始加载与后续分页加载应可区分。</li><li>“集合本来为空”和“筛选后无结果”提供不同下一步。</li><li>筛选、排序、搜索、分页和选中项的组合规则明确。</li><li>批量选择跨页是否保留，选择范围必须可见。</li><li>数据更新、删除或权限变化后，列表位置和焦点有合理落点。</li><li>虚拟滚动不能破坏键盘访问、屏幕阅读器集合信息或浏览器查找等关键能力。</li></ul><h2 id="详情设计" tabindex="-1">详情设计 <a class="header-anchor" href="#详情设计" aria-label="Permalink to &quot;详情设计&quot;">​</a></h2><p>详情页应先呈现对象身份、当前状态、主要操作和完成当前任务所需的关键属性。次要元数据、历史记录和关联对象按用户任务分组，而不是按数据库字段顺序罗列。</p><p>主要操作应随对象状态变化。例如“已归档项目”不再显示“发布”为主要操作；没有编辑权限时，界面应避免展示最终必定失败的操作，或在操作前明确权限申请路径。</p><p>需要覆盖：加载、对象不存在、已删除、无权限、内容过期、并发更新、局部模块失败和操作成功。删除当前对象后，应进入仍然有效的父级或列表，并说明结果。</p><h2 id="完整案例-项目管理后台" tabindex="-1">完整案例：项目管理后台 <a class="header-anchor" href="#完整案例-项目管理后台" aria-label="Permalink to &quot;完整案例：项目管理后台&quot;">​</a></h2><h3 id="任务" tabindex="-1">任务 <a class="header-anchor" href="#任务" aria-label="Permalink to &quot;任务&quot;">​</a></h3><p>项目管理员要找到逾期项目、确认负责人并调整截止日期。</p><h3 id="结构设计" tabindex="-1">结构设计 <a class="header-anchor" href="#结构设计" aria-label="Permalink to &quot;结构设计&quot;">​</a></h3><ol><li>全局导航当前项为“项目”，页面主标题为“项目”。</li><li>列表默认按最近更新排序，提供“逾期”筛选；筛选结果数通过可感知状态消息更新。</li><li>每行展示项目名、负责人、截止日期和状态。截止日期使用可比较的统一格式。</li><li>选择项目进入详情，URL 包含项目 ID；浏览器返回后恢复筛选和滚动位置。</li><li>详情首部显示项目名、逾期状态、负责人和“修改截止日期”。</li><li>编辑表单解释允许的日期范围；提交时执行客户端格式校验和服务端业务校验。</li><li>成功后详情显示新日期并宣布更新结果；失败时保留输入，错误关联到字段。</li></ol><h3 id="边界状态" tabindex="-1">边界状态 <a class="header-anchor" href="#边界状态" aria-label="Permalink to &quot;边界状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>界面行为</th></tr></thead><tbody><tr><td>没有任何项目</td><td>解释集合为空，并在有权限时提供新建入口</td></tr><tr><td>“逾期”筛选无结果</td><td>保留筛选条件，提供清除筛选</td></tr><tr><td>项目被他人删除</td><td>详情显示对象不存在，返回项目列表</td></tr><tr><td>截止日期被他人更新</td><td>提示版本冲突，展示最新值，让用户比较后重试</td></tr><tr><td>用户失去编辑权限</td><td>保持详情可读，移除或禁用编辑并说明申请路径</td></tr></tbody></table><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>建立对象、对象状态、用户任务和权限清单。</li><li>划分全局、局部和上下文导航，验证每个目的地名称。</li><li>为集合确定识别与比较属性，再选择列表、表格或卡片。</li><li>定义筛选、排序、分页、选择和 URL 状态的组合规则。</li><li>为详情排序身份、状态、主要操作、关键属性和历史信息。</li><li>按用户准备信息的顺序组织表单，写出每个字段和跨字段规则。</li><li>补齐四类结构的加载、空、失败、权限、过期和并发状态。</li><li>在窄屏、键盘、屏幕阅读器和真实长度数据下验证完整任务。</li></ol><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><ul><li>导航层级、URL、标题和当前项不一致。</li><li>用 Tab 模拟跨层级导航，导致返回与深链行为混乱。</li><li>只用 placeholder 作为表单标签，输入后失去字段含义。</li><li>客户端校验通过就假设提交一定成功。</li><li>列表展示很多字段，却没有支持真实比较任务。</li><li>筛选无结果与集合为空使用相同文案和操作。</li><li>详情把所有操作都设为主要按钮，忽略对象状态与风险。</li><li>删除对象后留在失效详情，没有下一步与焦点管理。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>直接打开三个层级不同的深链，检查标题、当前导航和面包屑。</li><li>只用键盘完成筛选、打开详情、编辑、处理错误和返回列表。</li><li>用屏幕阅读器核对地标、标题、表单标签、错误、列表或表格语义以及动态结果数。</li><li>准备零条、一条、数百条、超长名称和缺失字段数据，检查布局与信息优先级。</li><li>制造加载失败、提交失败、对象删除、权限变化和并发更新。</li><li>在窄屏完成同一任务，确认信息没有因布局变化而丢失，操作顺序仍合理。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>设计一个“工单列表 → 工单详情 → 修改优先级”的完整流程。</p><p>完成时应满足：</p><ul><li>标出全局、局部和上下文导航；</li><li>说明列表项的主标识、比较属性、默认排序和筛选规则；</li><li>详情按对象身份、状态、操作和属性组织；</li><li>表单具有标签、说明、校验时机和错误恢复；</li><li>覆盖空、筛选无结果、加载失败、无权限和并发更新；</li><li>写出键盘顺序、焦点落点和动态状态的辅助技术通知；</li><li>测试者能够依据完成标准判定任务是否成功。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/tutorials/page-structure/" target="_blank" rel="noreferrer">W3C WAI：Page Structure Tutorial</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/tutorials/forms/" target="_blank" rel="noreferrer">W3C WAI：Forms Tutorial</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Patterns</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-17）</li><li><a href="https://design-system.service.gov.uk/components/" target="_blank" rel="noreferrer">GOV.UK Design System：Components</a>（访问日期：2026-07-17）</li></ul>`,53)])])}const b=t(r,[["render",n]]);export{c as __pageData,b as default};
